const crypto = require('crypto');

const items = $input.all();
const results = [];

for (const item of items) {
  const html = item.json.body || item.json.data || '';

  // Extract meaningful text content (strip HTML tags, scripts, styles)
  const cleanText = html
    .replace(/<script[^>]*>[\s\S]*?<\/script>/gi, '')
    .replace(/<style[^>]*>[\s\S]*?<\/style>/gi, '')
    .replace(/<[^>]+>/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();

  // Generate content hash
  const currentHash = crypto.createHash('md5').update(cleanText).digest('hex');

  // Get stored hash from static data
  const staticData = $getWorkflowStaticData('global');
  const previousHash = staticData.lastHash || null;
  const previousTimestamp = staticData.lastChecked || null;

  const hasChanged = previousHash !== null && previousHash !== currentHash;
  const isFirstRun = previousHash === null;

  // Store current state
  staticData.lastHash = currentHash;
  staticData.lastChecked = new Date().toISOString();
  staticData.lastContent = cleanText.substring(0, 5000); // Store truncated for diff

  results.push({
    json: {
      url: item.json.url || $env.MONITOR_URL || 'https://example.com/pricing',
      current_hash: currentHash,
      previous_hash: previousHash,
      has_changed: hasChanged,
      is_first_run: isFirstRun,
      checked_at: new Date().toISOString(),
      previous_check: previousTimestamp,
      content_preview: cleanText.substring(0, 500),
      status_code: item.json.statusCode || 200
    }
  });
}

return results;

const d = $input.first().json;
const url = d.url;
const timestamp = d.checked_at;
const preview = d.content_preview || 'N/A';

const telegramMsg = [
  '\ud83d\udea8 *Website Change Detected!*',
  '',
  `\ud83c\udf10 *URL:* ${url}`,
  `\u23f0 *Detected:* ${timestamp}`,
  `\ud83d\udd0d *Previous Check:* ${d.previous_check || 'N/A'}`,
  '',
  '*Content Preview:*',
  `\`\`\`${preview.substring(0, 300)}\`\`\``,
  '',
  '_Check the website for full details._'
].join('\n');

const slackMsg = {
  text: `:rotating_light: *Website Change Detected*\n\n*URL:* ${url}\n*Time:* ${timestamp}\n*Previous Hash:* \`${d.previous_hash}\`\n*New Hash:* \`${d.current_hash}\`\n\n*Preview:*\n>>> ${preview.substring(0, 500)}`
};

const emailSubject = `[Alert] Website Changed: ${url}`;
const emailBody = `A change was detected on the monitored website.\n\nURL: ${url}\nDetected: ${timestamp}\nPrevious Check: ${d.previous_check || 'First run'}\n\nContent Preview:\n${preview}\n\n---\nAutomated by n8n Website Monitor`;

return [{
  json: {
    ...d,
    telegram_message: telegramMsg,
    slack_message: slackMsg.text,
    email_subject: emailSubject,
    email_body: emailBody
  }
}];
